  %add = add <vscale x 8 x i32> %0, shufflevector (<vscale x 8 x i32> insertelement (<vscale x 8 x i32> poison, i32 4, i64 0), <vscale x 8 x i32> poison, <vscale x 8 x i32> zeroinitializer)
  ret <vscale x 8 x i32> %add
}

